var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"투화님. 문제가 생겼습니다.","JPN":"投花様、問題が発生しました。","ENG":"Ms. Flora. A problem has arisen.","TWN":"投花師姐，出事了。"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"오늘은 꽃술 향이 좋네. 너도 마실래?","JPN":"今日は花酒の香りがやけに良い。お前も飲むか？","ENG":"The scent of today's floral spirit is nice. Would you also like a sip?","TWN":"今天的花酒很香呢，你要來一杯嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"아, 네… 감사합니다.","JPN":"あ、はい……ありがとうございます。","ENG":"Oh, yes... Thank you.","TWN":"喔，好…謝謝。"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그래서, 뭐가 문제지?","JPN":"それで、何があった？","ENG":"So? What might be the problem?","TWN":"所以是出什麼事？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"문주님이 그 파문인에게 노려지고 있는 것 같습니다.","JPN":"門主様があの追放者に狙われているようです。","ENG":"We believe that our sect leader is being targeted by that outcast.","TWN":"幫主似乎被那個逐出師門的人給盯上了。"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"살수들을 파견할까요?","JPN":"刺客を送り込みましょうか？","ENG":"Shall I deploy the assassins?","TWN":"要派殺手嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"뭐 하러?","JPN":"どうしてだ？","ENG":"What for?","TWN":"為何要派？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"그야 문주님의 신변에 위험이 생길 수 있고…","JPN":"それは、門主様の身に危険が及ぶかもしれませんし……","ENG":"Because our sect leader is in danger...","TWN":"我擔心幫主可能會有危險…"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"만일 그 자가 결투에서 이겨 백서의 문주가 되기라도 한다면…","JPN":"もしその者が決闘で勝利し、白西の門主になるようなことでもあれば……","ENG":"And if that man wins the battle and becomes the leader of White West...","TWN":"萬一他在決鬥中獲勝成為白西的幫主…"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"전통을 지켜야 할 우리가 섭리음양의 법칙을 먼저 깨부수는 건 곤란해.","JPN":"伝統を守っていく立場の私たちが燮理陰陽のルールを自ら破ることはできない。","ENG":"We are bound by tradition, and breaking the balance of yin and yang will not be tolerated.","TWN":"我們本該要遵守燮理陰陽的規矩，怎麼可以先破壞規矩呢？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"아무리 불명예스럽게 쫓겨난 파문인이라 해도, 그자 또한 간장의 조각을 가진 이상 평등한 백서의 도전자이니까.","JPN":"いくらあの者が不祥事によって追放された身だとしても、干将の欠片を持っている以上、あの者もまた白西の正当な挑戦者だからな。","ENG":"No matter how dishonorably this man has been excommunicated, he still wields the shard of Kanshou. Thus, he has the right to challenge her without question.","TWN":"雖然他是做了不光榮的事才被逐出師門的，但他身上也有干將的碎片，那他就應該有公平競爭的機會。"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"괜찮을까요?","JPN":"それで大丈夫なんでしょうか？","ENG":"Will she be okay?","TWN":"這樣沒問題嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"걱정 마. 문주님의 혈귀라는 별호는 단지 멋으로 붙은 게 아니거든.","JPN":"心配するな。門主様の血鬼という異名は、伊達じゃないのだ。","ENG":"Do not worry. Her nickname of Bloodseeker is not just for show.","TWN":"放心，你以為幫主血鬼的稱號只是取好聽的嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"설마, 장문인께서 내게 맡긴 문주 자리를 고작 사사로운 정 때문에 그 애한테 넘긴 거라고 생각하니?","JPN":"まさか、掌門人が私に任せた門主の座をただの人情で師妹に譲ったと思うか？","ENG":"Or, do you think that I yielded the seat of sect leader to her because of some trivial attachment I have toward her?","TWN":"你以為掌門人只是因為個人喜好，就將原本要託付於我的幫主之位交給她嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"그 자와 엮이게 될 것까지… 예상하고 계셨던 겁니까?","JPN":"あの者といずれ交わることになることを……見越してのことだったのでしょうか？","ENG":"Then you already predicted... that he would approach her?","TWN":"意思是掌門人他…早就料到那個人會來糾纏幫主嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"파문인 타오는 흑동의 여러 골칫거리들 중 하나일 뿐이야.","JPN":"追放者であるタオは黒東にある数多くの問題事の一つに過ぎない。","ENG":"The outcast known as Tao is one of many nuisances for Black East.","TWN":"被逐出師門的陶只是黑東的眾多麻煩之一。"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그리고 장문인이 계시던 과거와 달리 지금 세상은 어딜 가나 괴물천지잖아.","JPN":"そして掌門人がまだいらっしゃった昔とは違い、今の世はどこも怪物だらけだ。","ENG":"Furthermore, the world is full of monsters, unlike during the previous sect master's time.","TWN":"況且，不同於過去掌門人還在世時，現在的世界怪物無所不在。"},"stage":{"bg":"CLAN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"이런 엉망진창 산해경 속에서…","JPN":"こんなめちゃくちゃな世界で……","ENG":"In this torrent of chaos...","TWN":"在這一塌糊塗的山海經中…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"우리도 괴물을 등에 업어야 살아남지 않겠어?","JPN":"我々自身も怪物を抱えていなきゃ、生き残るのは不可能だと思わないか？","ENG":"It would be wise to have a monster on our side as well.","TWN":"我們也必須將怪物揹在背上才能存活不是嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제법이군요. 먼저 지치는 건 그쪽이 될 것 같지만.","JPN":"やりますね。先に力尽きるのはあなたの方だと思いますが。","ENG":"Impressive. But it seems that you will be the first one to be worn out.","TWN":"身手不錯，但應該是你會先累。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하… 너도 굉장하네. 이쪽도 한때는 나름 백서에서 으뜸가는 천재였는데 말이지.","JPN":"はは……お前も結構な怪物だったんだな。こっちは一時、白西で有名な天才だったんだけどな。","ENG":"Haha... Not bad yourself. You know, I was once a prodigy of White West myself.","TWN":"哈哈…你也很不錯。好歹我也曾經是白西裡首屈一指的天才。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어째서, 당신 같은 강자가 규율을 어기면서까지 강함에 집착하는 거죠?","JPN":"いったいどうして、あなたのような強者が、規律を破ってまで強さに執着するのですか？","ENG":"Then why would a prodigy like you break the rules for power?","TWN":"像你這麼厲害的人，為何不惜違反門規也要執著於能力呢?"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"힘을 취하고자 하는 사람의 본능에, 굳이 규율을 논할 필요가 있나?","JPN":"力を欲する人間の本能の前に、規律になんの意味があるだろうか？","ENG":"Wanting power is a human instinct. Rules don't matter.","TWN":"這是追求能力之人的本能，何須談什麼規矩？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"으윽…! 이거 놔…!","JPN":"くっ……離せ……！","ENG":"Ngh...! Get off me!","TWN":"呃…！放開我…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이런! 학생에게 무슨 짓을…!","JPN":"なっ！　我が生徒に何を……！","ENG":"No! What are you doing to him...?!","TWN":"你做什麼！你放開他…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하… 인질의 목에 칼만 들이대면 꼼짝 못하는 꼴이라니. 너무 쉽잖아.","JPN":"はは……人質の首にナイフを当てるだけでどいつもこいつも止まるなんて、簡単すぎないか。","ENG":"Haha... Can't move when I have a knife to his neck? This is too easy.","TWN":"哈哈…只要將刀架在人質的脖子上，你就無法出手嗎？還真容易呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"애초에 누구의 목숨도 신경 쓰지 않으면, 남에게 발목 잡히는 귀찮은 일도 없을 텐데 말이야.","JPN":"他人の命なんて気にしなければ、他人に足を引っ張られることもないだろうにな。","ENG":"If you didn't care about anyone's life, there wouldn't be anything getting in your way.","TWN":"只要不在乎任何人的性命，就不會有被人逮到把柄的麻煩事發生。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"콜록콜록…","JPN":"ゲホゲホ……","ENG":"*Cough, Cough!*","TWN":"呃呃呃…"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"좋아. 놓아줄게. 구질구질한 인질극은 관두자고.","JPN":"まぁいい、放してやる。ねちっこい人質取りはもうやめだ。","ENG":"Fine. I'll let him free. This hostage-captor roleplaying was getting old anyway.","TWN":"好，就放開你吧。挾持人質的齷齪戲碼到此結束。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"마침 이번에 새로 정제한 약을 시험하고 싶던 참이었어.","JPN":"丁度新しく出来上がった薬を試してみたかったんだ。","ENG":"Also, I've been meaning to test out this new drug I concocted.","TWN":"我正好想試試這次新做的藥。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Kgh?!","TWN":"唔？！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"어때? 아까와는 힘의 차원이 다르지?","JPN":"どうだ？　さっきとはまるでパワーが違うだろう？","ENG":"How's this? My power is leagues beyond what it was, no?","TWN":"如何？力量和剛才完全是不同層級吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"이 엘릭서야말로, 내가 가진 천부적인 재능의 원천이거든.","JPN":"このエリクサーこそ、僕の持つ天賦の才能の源なんだ。","ENG":"This Elixir is the source of all my innate talents!","TWN":"這個聖水才是我所有才能的泉源。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"윽…!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃…！"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"자, 일어나.","JPN":"さあ、起きろ。","ENG":"Get up.","TWN":"起來。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"피 좀 흘렸다고 벌써 항복하려는 건 아니지?","JPN":"その程度のダメージで、もう降伏するつもりじゃないよな？","ENG":"You're not gonna surrender just because of some flesh wound, right?","TWN":"你應該不會才流一點血就想投降吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…그럼요.","JPN":"……当たり前です。","ENG":"...Absolutely not.","TWN":"…不會。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저는 아직 검을 뽑지도 않았으니까요.","JPN":"私はまだ剣すら抜いていません。","ENG":"I have not even unsheathed my sword.","TWN":"我都還沒拔劍呢。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"피…… 냄새.","JPN":"血の……におい。","ENG":"The smell... of blood.","TWN":"血……的味道。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어째서 그런 결정이 난 거요?","JPN":"どうしてそんな決定が下されたんでしょうか？","ENG":"How did it come to this decision?","TWN":"為何會做出這樣的決定？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"나야 모르지. 사매를 이번 임무에서 열외시키라고 명한 건 장문인이신걸?","JPN":"私にもわからない。なんせ師妹を今回の任務から外すように命じたのは掌門人だ。","ENG":"I don't know. It was the sect master who ordered that you be excluded from this mission.","TWN":"我怎麼知道？是掌門人說將師妹排除在這次任務之外的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"지난 번에도, 그 전에도 그랬소. 본인은 한 번도 사부님을 실망시킨 적이 없단 말이오.","JPN":"前回も、前々回もそうだ。自分で一度も師匠を失望させたことはないはずです。","ENG":"This happened last time, and the time before. I have never disappointed the master.","TWN":"上次和之前也都是這樣，我明明未曾令師父失望過。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"나도 잘은 모르지만, 아마 장문인께서 우려하시는 건 사매의 실력이 아닐 거야.","JPN":"よくわからないが、おそらく掌門人が憂いているのは師妹の実力ではないはずだ。","ENG":"I'm in the dark as much as you are. However, I believe that the master is not concerned about your skills.","TWN":"我也不太清楚，但我猜掌門人擔心的不是你的能力。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇다면 대체 무엇 때문에…!","JPN":"だとしたら、いったいどうして……！","ENG":"Then why would he...?!","TWN":"那到底是為什麼…！"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"사매는 우리가 함께 구룡왕을 암살하던 날을 기억해?","JPN":"師妹は一緒に九龍王を暗殺した日のことを覚えているか？","ENG":"Do you remember the night we assassinated the Kowloon King?","TWN":"師妹，你記得我們一起暗殺九龍王的那一天嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"젊은 시녀가 구룡왕을 감싸려다 칼에 베여 피를 흘렸고…","JPN":"若い侍女が九龍王を庇おうとして、刀で斬られ、血を流し……","ENG":"A young handmaiden tried to protect him and started bleeding from her wound...","TWN":"我只記得年輕的侍女為了保護九龍王，被刀劃傷流血…"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 뒤는… 구룡왕이 도망쳐 임무를 실패했다는 것 외엔 기억이 잘 나지 않소.","JPN":"そこからは……九龍王に逃げられ、任務に失敗したということ以外は覚えていません。","ENG":"But after that... I only recall that he fled and that our mission failed.","TWN":"後來…九龍王逃跑，任務失敗，除此之外我什麼也不記得。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그때 네가 보였던 모습은 뭐랄까…","JPN":"その時の師妹の姿……","ENG":"The way you looked at that time...","TWN":"那時候的你看起來，該怎麼說呢…"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"나도 좀 무서웠거든.","JPN":"私でさえ恐怖を覚えるものだった。","ENG":"It also had me frightened.","TWN":"連我都覺得有點恐怖。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN_003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"뭘 멈추고 그래? 계속 덤벼봐.","JPN":"何を躊躇っているんだ？　かかってこいよ。","ENG":"What are you waiting for? Come at me!","TWN":"怎麼停下來了？再來啊！"},"stage":{"bg":"CLAN_003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘…?","JPN":"シエルさん……？","ENG":"Ciel...?","TWN":"希爾…？"},"stage":{"bg":"CLAN_003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"음?","JPN":"む？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CLAN_003","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"<color=#ff3636>달콤한…</color>","JPN":"<color=#ff3636>甘い……</color>","ENG":"<color=#ff3636>The sweet scent...</color>","TWN":"<color=#ff3636>甜甜的…</color>"},"stage":{"bg":"CLAN_003","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_11"},{"id":"L46_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"<color=#ff3636>피 냄새…</color>","JPN":"<color=#ff3636>血の匂い……</color>","ENG":"<color=#ff3636>Of blood...</color>","TWN":"<color=#ff3636>血腥味…</color>"},"stage":{"bg":"CLAN_003","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SCHOOL_C_STAFF_IN_TRAILER_12"},{"id":"L4_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"너…?","JPN":"お前……！","ENG":"You...?","TWN":"你…？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"그런 몸상태로… 카운터 구속용 사슬을 전부 끊어냈다고?","JPN":"その状態で……カウンター拘束用の鎖を全部絶っただと？","ENG":"You broke all the Counter restraints... with those injuries?","TWN":"你傷得那麼重…還能掙脫制裁者專用鎖鏈？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_CIEL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};